"use strict";class cmspid{static encode(e){if(!e&&""!==e)return"";let t;if(Buffer.isBuffer(e))t=e;else{if("string"!=typeof e)throw new TypeError("cmspid: Input must be a String or a Buffer.");t=Buffer.from(e,"utf8")}const r=t.toString("hex");return this._tokenize(r)}static decode(e,t="utf8"){if("string"!=typeof e)throw new TypeError("cmspid: Decode parameter must be a string.");const r=e.replace(/-/g,"");try{const e=Buffer.from(r,"hex");return"buffer"===t?e:e.toString(t)}catch(e){throw new Error("cmspid: Failed to decode. String may be corrupted or not a valid hex sequence.")}}static isValid(e){return/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]+$/i.test(e)}static _tokenize(e){const t=[],r=[8,4,4,4];let o=0;for(const i of r)o<e.length&&(t.push(e.substring(o,o+i)),o+=i);return o<e.length&&t.push(e.substring(o)),t.join("-")}}"undefined"!=typeof module&&module.exports&&(module.exports=cmspid),"undefined"!=typeof window&&(window.cmspid=cmspid);
